css:
.loader {color: var(--loader-color, #38bdf8);
  --loader-secondary-color: #f472b6;

  position: relative;
  width: 200px;
  overflow: hidden;
  height: 200px;
  background: #c9d5e0;
  border-radius: 50px;
  transform-style: preserve-3d;
  mix-blend-mode: hard-light;
  box-shadow:
    25px 25px 25px -5px color-mix(in srgb, var(--loader-color, #38bdf8) 45%, transparent),
    inset 15px 15px 10px color-mix(in srgb, var(--loader-bg, #e2e8f0) 75%, transparent),
    -15px -15px 30px color-mix(in srgb, var(--loader-bg, #e2e8f0) 55%, transparent),
    inset -1px -1px 10px color-mix(in srgb, var(--loader-color, #38bdf8) 45%, transparent);
}

.circle {
  position: absolute;
  inset: 35px;
  background: #acbaca;
  border-radius: 50%;
  transform-style: preserve-3d;
  box-shadow:
    5px 5px 15px 0 #152b4a66,
    inset 5px 5px 5px color-mix(in srgb, var(--loader-bg, #e2e8f0) 55%, transparent),
    -6px -6px 10px rgba(255, 255, 255, 1);
}

.circle::before {
  content: "";
  position: absolute;
  inset: 4px;
  background: linear-gradient(#2196f3, #e91e63);
  mix-blend-mode: color-burn;
  border-radius: 50%;
  animation: anim 2s linear infinite;
}

.circle::after {
  content: "";
  position: absolute;
  inset: 25px;
  filter: blur(0.9px);
  background: #acbaca;
  border-radius: 50%;
  z-index: 1000;
}

@keyframes anim {
  0% {
    transform: rotate(0deg);
    filter: blur(2px);
  }
  100% {
    transform: rotate(360deg);
    filter: blur(4px);
  }
}
